import React, { useState } from 'react';
import './Forms.css';

const API_URL = 'http://localhost:5000/api';

const AddDoctor = ({ onNavigate }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    specialization: '',
    licenseNumber: '',
    availableHours: '9:00 AM - 5:00 PM',
  });

  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  const specializations = [
    'Cardiology',
    'Neurology',
    'Pediatrics',
    'Orthopedics',
    'Dermatology',
    'General Medicine',
    'Psychiatry',
    'ENT',
    'Ophthalmology',
    'Gastroenterology',
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Validation
    if (!formData.firstName || !formData.lastName || !formData.email || !formData.specialization || !formData.licenseNumber) {
      setError('Please fill in all required fields');
      return;
    }

    try {
      setLoading(true);
      setError('');

      const response = await fetch(`${API_URL}/doctors`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const result = await response.json();

      if (result.success) {
        setSuccessMessage(`Dr. ${formData.firstName} ${formData.lastName} added successfully!`);
        setSubmitted(true);

        setTimeout(() => {
          setFormData({
            firstName: '',
            lastName: '',
            email: '',
            phone: '',
            specialization: '',
            licenseNumber: '',
            availableHours: '9:00 AM - 5:00 PM',
          });
          setSubmitted(false);
          setSuccessMessage('');
        }, 2000);
      } else {
        setError(result.error || 'Failed to add doctor');
      }
    } catch (err) {
      console.error('Error:', err);
      setError('Unable to connect to server. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="form-container">
      <div className="form-header-section">
        <h1>👨‍⚕️ Add New Doctor</h1>
        <p>Register a new doctor to the hospital system</p>
      </div>

      {submitted && (
        <div className="success-message">
          <span className="success-icon">✓</span>
          <div>
            <strong>Doctor Added Successfully!</strong>
            <p>{successMessage}</p>
          </div>
        </div>
      )}

      {error && (
        <div className="error-message">
          <span className="error-icon">⚠️</span>
          <p>{error}</p>
        </div>
      )}

      <form className="registration-form" onSubmit={handleSubmit}>
        {/* Doctor Information */}
        <div className="form-section">
          <h2>Doctor Information</h2>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="firstName">First Name *</label>
              <input
                id="firstName"
                type="text"
                name="firstName"
                placeholder="Priya"
                value={formData.firstName}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label htmlFor="lastName">Last Name *</label>
              <input
                id="lastName"
                type="text"
                name="lastName"
                placeholder="Singh"
                value={formData.lastName}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="email">Email Address *</label>
              <input
                id="email"
                type="email"
                name="email"
                placeholder="doctor@hospital.com"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label htmlFor="phone">Phone Number</label>
              <input
                id="phone"
                type="tel"
                name="phone"
                placeholder="+91 98765 43210"
                value={formData.phone}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="specialization">Specialization *</label>
              <select
                id="specialization"
                name="specialization"
                value={formData.specialization}
                onChange={handleChange}
                required
              >
                <option value="">Select Specialization</option>
                {specializations.map(spec => (
                  <option key={spec} value={spec}>{spec}</option>
                ))}
              </select>
            </div>
            <div className="form-group">
              <label htmlFor="licenseNumber">License Number *</label>
              <input
                id="licenseNumber"
                type="text"
                name="licenseNumber"
                placeholder="MD/2015/001234"
                value={formData.licenseNumber}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="availableHours">Available Hours</label>
            <input
              id="availableHours"
              type="text"
              name="availableHours"
              placeholder="9:00 AM - 5:00 PM"
              value={formData.availableHours}
              onChange={handleChange}
            />
          </div>
        </div>

        {/* Form Actions */}
        <div className="form-actions">
          <button type="submit" className="btn-submit" disabled={loading}>
            {loading ? (
              <>
                <span className="spinner-small"></span> Adding...
              </>
            ) : (
              <>
                <span>✓</span> Add Doctor
              </>
            )}
          </button>
          <button
            type="button"
            className="btn-cancel"
            onClick={() => onNavigate('dashboard')}
            disabled={loading}
          >
            <span>✕</span> Cancel
          </button>
        </div>
      </form>
    </div>
  );
};

export default AddDoctor;
